text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표일은 스모크 테스트가 통과할 경우 금요일 15:00 KST로 정했다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 릴리스한다는 제안은 최종 결정되지 않았다."
      },
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경하자는 제안은 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스는 내부 스트레치 목표로만 언급되었고, 공개 릴리스 결정은 아니다."
      },
      {
        "goal": "README 설치 단계는 가능하면 목요일까지 검토하자는 의견이 있었지만, 담당자는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ],
    "non_decisions": [
      {
        "item": "고객 또는 외부 파트너명은 언급되지 않았고, 특정되지 않았다."
      },
      {
        "item": "README 설치 단계 검토는 필요성이 언급되었으나 담당자와 확정 일정은 정해지지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인은 Minjun의 스모크 결과 이후로만 진행되며, 정확한 마감 시각은 정해지지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "unassigned",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과",
      "Doyun의 금요일 12:00 KST 실패 triage 노트",
      "Hara가 확인한 tarball 경로",
      "최종 릴리스 승인 권한자",
      "릴리스 노트에 수요일 내부 스트레치 목표를 넣을지 여부"
    ],
    "what_not_to_invent": [
      "고객명",
      "예산",
      "보안 사고",
      "운영 장애",
      "법적 승인 요건",
      "미확정된 오너",
      "확정되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "고객 또는 외부 파트너는 특정하지 않는다.",
    "예산 정보는 추가하지 않는다.",
    "보안 사고는 추가하지 않는다.",
    "프로덕션 장애는 추가하지 않는다.",
    "법적 승인 요건은 추가하지 않는다.",
    "미지정 오너를 임의로 배정하지 않는다.",
    "명시되지 않은 마감일을 만들어내지 않는다.",
    "합의되지 않은 결정을 확정 사실처럼 쓰지 않는다."
  ]
}
